import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../services/axios';

const CATEGORIES = ['All', 'Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Other'];

function Home() {
  const [events, setEvents] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('All');
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchEvents(); }, []);

  useEffect(() => {
    let result = events;
    if (search) result = result.filter(e => e.name.toLowerCase().includes(search.toLowerCase()) || e.venue.toLowerCase().includes(search.toLowerCase()));
    if (category !== 'All') result = result.filter(e => e.category === category);
    setFiltered(result);
  }, [search, category, events]);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      setEvents(res.data.events || []);
      setFiltered(res.data.events || []);
    } catch {
      console.error('Failed to load events');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">

      {/* Hero */}
      <section className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 text-white py-20">
        <div className="max-w-6xl mx-auto px-4 text-center">
          <h1 className="text-5xl font-bold mb-4">Welcome to EventHub 🎉</h1>
          <p className="text-xl text-white/90 mb-8">Discover and book amazing events near you</p>

          {/* Search */}
          <div className="bg-white/20 backdrop-blur-md rounded-2xl p-4 max-w-2xl mx-auto">
            <input
              type="text"
              placeholder="🔍 Search events by name or venue..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full px-4 py-3 rounded-xl text-gray-800 focus:outline-none"
            />
          </div>
        </div>
      </section>

      {/* Category Filter */}
      <section className="bg-white shadow-sm py-4">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex gap-2 overflow-x-auto pb-2">
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setCategory(cat)}
                className={`px-4 py-2 rounded-full text-sm font-semibold whitespace-nowrap transition ${
                  category === cat
                    ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-md'
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}>
                {cat}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Events Grid */}
      <section className="py-12 px-4">
        <div className="max-w-7xl mx-auto">
          <div className="flex justify-between items-center mb-8">
            <h2 className="text-3xl font-bold text-gray-800">
              {category === 'All' ? 'All Events' : category}
              <span className="text-lg font-normal text-gray-500 ml-2">({filtered.length} events)</span>
            </h2>
          </div>

          {loading ? (
            <div className="text-center py-20">
              <div className="text-5xl mb-4 animate-bounce">🎉</div>
              <p className="text-gray-500 text-lg">Loading events...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-2xl shadow-sm">
              <div className="text-6xl mb-4">😕</div>
              <h3 className="text-2xl font-bold text-gray-700 mb-2">No events found</h3>
              <p className="text-gray-500">Try a different search or category</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filtered.map(event => (
                <div key={event._id} className="bg-white rounded-2xl shadow-sm overflow-hidden hover:shadow-xl hover:-translate-y-1 transition duration-300 flex flex-col">
                  <div className="relative">
                    <img src={event.image || 'https://via.placeholder.com/400x250?text=Event'}
                      alt={event.name} className="w-full h-48 object-cover" />
                    <span className="absolute top-3 left-3 bg-white/90 backdrop-blur text-blue-600 text-xs font-bold px-3 py-1 rounded-full">
                      {event.category}
                    </span>
                    {event.availableSeats === 0 && (
                      <span className="absolute top-3 right-3 bg-red-500 text-white text-xs font-bold px-3 py-1 rounded-full">
                        SOLD OUT
                      </span>
                    )}
                  </div>
                  <div className="p-5 flex flex-col flex-1">
                    <h3 className="text-lg font-bold text-gray-800 mb-2 line-clamp-1">{event.name}</h3>
                    <p className="text-gray-500 text-sm mb-1">📅 {new Date(event.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })} • {event.time}</p>
                    <p className="text-gray-500 text-sm mb-3 line-clamp-1">📍 {event.venue}</p>
                    <div className="flex justify-between items-center mt-auto pt-3 border-t border-gray-100">
                      <span className="text-blue-600 font-bold text-lg">₹{event.price}</span>
                      <span className="text-gray-400 text-xs">{event.availableSeats} seats left</span>
                    </div>
                    <Link to={`/events/${event._id}`}
                      className={`mt-3 w-full text-center py-2.5 rounded-xl font-semibold text-sm transition ${
                        event.availableSeats === 0
                          ? 'bg-gray-100 text-gray-400 cursor-not-allowed pointer-events-none'
                          : 'bg-gradient-to-r from-blue-600 to-purple-600 text-white hover:shadow-lg'
                      }`}>
                      {event.availableSeats === 0 ? 'Sold Out' : 'Book Now 🎟️'}
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA */}
      <section className="bg-gradient-to-r from-purple-600 to-pink-600 py-16 text-center text-white">
        <div className="max-w-4xl mx-auto px-4">
          <h2 className="text-4xl font-bold mb-3">Ready to Start Your Journey?</h2>
          <p className="text-white/90 text-lg mb-6">Join thousands of event-goers today!</p>
          <Link to="/register" className="inline-block bg-white text-purple-600 px-8 py-3 rounded-full font-bold hover:scale-105 transition">
            Sign Up Free 🚀
          </Link>
        </div>
      </section>
    </div>
  );
}

export default Home;
